import React, { useState } from "react";
import { ArrowLeft } from "lucide-react";

export default function WithdrawScreen({ onWithdraw, onBack, darkMode }) {
  const [amount, setAmount] = useState("");
  const [status, setStatus] = useState(null); // success | error

  const handleWithdraw = () => {
    if (!amount || Number(amount) <= 0) {
      setStatus("error");
      return;
    }

    onWithdraw(Number(amount));
    setStatus("success");
    setAmount("");
  };

  return (
    <div
      className={`min-h-screen px-5 pt-6 pb-24 ${
        darkMode ? "bg-gray-900" : "bg-[#f4f6fb]"
      }`}
    >
      {/* Header */}
      <div className="flex items-center gap-3 mb-8">
        <button onClick={onBack}>
          <ArrowLeft
            className={`w-6 h-6 ${darkMode ? "text-gray-300" : "text-gray-700"}`}
          />
        </button>
        <h1
          className={`text-xl font-semibold ${
            darkMode ? "text-white" : "text-gray-900"
          }`}
        >
          Withdraw Money
        </h1>
      </div>

      {/* Card */}
      <div
        className={`rounded-2xl p-6 shadow-sm ${
          darkMode
            ? "bg-gray-800 shadow-gray-700"
            : "bg-white shadow-sm"
        }`}
      >
        <label className={`text-sm ${darkMode ? "text-gray-400" : "text-gray-500"}`}>
          Enter amount
        </label>

        <input
          type="number"
          placeholder="₦0.00"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          className={`mt-3 w-full text-2xl font-semibold outline-none border-b pb-2 ${
            darkMode
              ? "border-gray-600 text-white placeholder-gray-400 bg-gray-800"
              : "border-gray-300 text-gray-900 placeholder-gray-400 bg-white"
          }`}
        />

        {/* Status message */}
        {status === "success" && (
          <p className="mt-3 text-sm text-emerald-500">Withdrawal successful</p>
        )}

        {status === "error" && (
          <p className="mt-3 text-sm text-red-500">Enter a valid amount</p>
        )}

        <button
          onClick={handleWithdraw}
          className="mt-8 w-full bg-emerald-600 text-white py-4 rounded-xl font-semibold active:scale-[0.98] transition"
        >
          Continue
        </button>
      </div>
    </div>
  );
}
